+import { $internal } from '../common';
+import { createEntity, destroyEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { getRelationTargets, hasRelationPair } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { DeferredBuffer, World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Buffer = DeferredBuffer & { commands: Command[]; flushing: boolean };
+
+export function createDeferredBuffer(world: World): Buffer {
+    const buffer: Buffer = {
+        commands: [],
+        flushing: false,
+        // Allocate now so a deferred spawn is immediately usable as a relation target.
+        // Its traits are still invisible to queries until this buffer is flushed.
+        spawn(...traits) {
+            const entity = createEntity(world);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            buffer.commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            buffer.commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            buffer.commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            buffer.commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushBuffer(world, buffer);
+        },
+    };
+    return buffer;
+}
+
+export function activeDeferred(world: World): Buffer {
+    const ctx = world[$internal];
+    return (ctx.deferredStack[ctx.deferredStack.length - 1] ?? ctx.deferredRoot) as Buffer;
+}
+
+export function enterDeferredScope(world: World): Buffer {
+    const buffer = createDeferredBuffer(world);
+    world[$internal].deferredStack.push(buffer);
+    return buffer;
+}
+
+export function exitDeferredScope(world: World, buffer: Buffer) {
+    const stack = world[$internal].deferredStack;
+    if (stack[stack.length - 1] !== buffer) return;
+    try {
+        buffer.flush();
+    } finally {
+        stack.pop();
+    }
+}
+
+/** A normal mutation is an ordering boundary for any pending command. */
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    const ctx = world[$internal];
+    const buffers = [ctx.deferredRoot, ...ctx.deferredStack] as Buffer[];
+    if (buffers.some((buffer) => !buffer.flushing && buffer.commands.some((c) => c.entity === entity))) {
+        for (const buffer of buffers) buffer.flush();
+    }
+}
+
+function flushBuffer(world: World, buffer: Buffer) {
+    if (buffer.flushing || buffer.commands.length === 0) return;
+    buffer.flushing = true;
+    const commands = buffer.commands.splice(0);
+    try {
+        // A freshly spawned entity that is also destroyed has no observable state.
+        const nullified = new Set<Entity>();
+        const spawned = new Set<Entity>();
+        for (const command of commands) {
+            if (command.type === 'spawn') spawned.add(command.entity);
+            else if (command.type === 'destroy' && spawned.has(command.entity)) nullified.add(command.entity);
+        }
+        for (const command of commands) {
+            if (nullified.has(command.entity)) continue;
+            if (!world.has(command.entity)) {
+                // World entity destruction is a programmer error; stale normal entities are benign.
+                if (command.type === 'destroy' && command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+                }
+                continue;
+            }
+            switch (command.type) {
+                case 'spawn':
+                    applyAdd(world, command.entity, command.traits);
+                    break;
+                case 'destroy':
+                    destroyEntity(world, command.entity);
+                    break;
+                case 'add':
+                    applyAdd(world, command.entity, command.traits);
+                    break;
+                case 'remove':
+                    removeTrait(world, command.entity, ...command.traits);
+                    break;
+                case 'exclusive': {
+                    const { relation, target } = command.pair[$internal];
+                    removeTrait(world, command.entity, relation('*'));
+                    if (target !== '*') addTrait(world, command.entity, command.pair);
+                    break;
+                }
+            }
+        }
+        // Release nullified spawns after every command has been skipped.
+        for (const entity of nullified) if (world.has(entity)) destroyEntity(world, entity);
+    } finally {
+        buffer.flushing = false;
+    }
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        addTrait(world, entity, config);
+        if (isRelationPair(config)) {
+            const { params } = config[$internal];
+            if (params && hasRelationPair(world, entity, config)) setTrait(world, entity, config, params, false);
+        } else if (Array.isArray(config) && hasTrait(world, entity, config[0])) {
+            setTrait(world, entity, config[0], config[1], false);
+        }
+    }
+}
+
+export function hasDeferred(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const buffers = [world[$internal].deferredRoot, ...world[$internal].deferredStack] as Buffer[];
+    const commands = buffers.flatMap((buffer) => buffer.commands).filter((command) => command.entity === entity);
+    if (commands.length === 0) return undefined;
+    let result = isRelationPair(trait)
+        ? hasRelationPair(world, entity, trait)
+        : hasTrait(world, entity, trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') return false;
+        if (command.type === 'add') {
+            for (const item of command.traits) if (matches(item, trait)) result = true;
+        } else if (command.type === 'remove') {
+            for (const item of command.traits) if (matches(item, trait) || clearsPair(item, trait)) result = false;
+        } else if (command.type === 'exclusive' && isRelationPair(trait)) {
+            const pair = command.pair;
+            if (pair[$internal].relation === trait[$internal].relation) {
+                result = pair[$internal].target !== '*' && pair[$internal].target === trait[$internal].target;
+            }
+        }
+    }
+    return result;
+}
+
+export function getDeferred(world: World, entity: Entity, trait: Trait | RelationPair): any | undefined {
+    const present = hasDeferred(world, entity, trait);
+    if (present === undefined) return undefined;
+    if (!present) return undefined;
+    let value = getTrait(world, entity, trait);
+    const buffers = [world[$internal].deferredRoot, ...world[$internal].deferredStack] as Buffer[];
+    for (const command of buffers.flatMap((buffer) => buffer.commands)) {
+        if (command.entity !== entity || command.type !== 'add') continue;
+        for (const item of command.traits) {
+            if (isRelationPair(item) && isRelationPair(trait) && matches(item, trait)) value = item[$internal].params ?? value;
+            else if (Array.isArray(item) && !isRelationPair(trait) && item[0] === trait) value = item[1];
+        }
+    }
+    return value;
+}
+
+function matches(item: ConfigurableTrait | Trait | RelationPair, trait: Trait | RelationPair) {
+    if (isRelationPair(item) || isRelationPair(trait)) {
+        return isRelationPair(item) && isRelationPair(trait) && item[$internal].relation === trait[$internal].relation && item[$internal].target === trait[$internal].target;
+    }
+    return (Array.isArray(item) ? item[0] : item) === trait;
+}
+
+function clearsPair(item: Trait | RelationPair, trait: Trait | RelationPair) {
+    return isRelationPair(item) && isRelationPair(trait) && item[$internal].relation === trait[$internal].relation && item[$internal].target === '*';
+}
